VALUES
  ('elementary-d0d1b9a2-moex-00095', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00096', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列何種情形應認列應付帳款？', '["賒購之進貨採起運點交貨之條件，目前商品仍在途", "賒購之進貨採目的地交貨之條件，目前商品仍在途", "賒銷之銷貨採起運點交貨之條件，目前商品仍在途", "賒銷之銷貨採目的地交貨之條件，目前商品仍在途"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00097', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '若記錄現銷商品$5,000時將貸方誤記為應收帳款，則對試算表之影響為何？', '["借貸方之總餘額均少計$5,000", "借貸方之總餘額均多計$5,000", "僅借方之總餘額多計$10,000", "借貸方之總餘額均無影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00098', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '辛公司X2年1月1日因銷貨收到客戶兩年期不附息票據，辛公司誤以票據之面額入帳，X2年12月31 日亦未進行調整分錄。此錯誤對於X2年12月31日財務報表相關項目之影響，下列何者錯誤？', '["應收票據被高估", "銷貨收入被高估", "利息收入被低估", "現金被低估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00099', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司 X3 年 12 月 31 日有庫存現金若干、活期存款$200,000、支票存款$300,000、借款之補償性回存 $10,000、未到期之遠期支票$5,000、自投資日起算三個月內到期之短期票券$20,000、員工借款$30,000。 若X3年12月31日正確之現金與約當現金餘額為$550,000，則甲公司X3年12月31日庫存現金應為 多少？', '["$30,000", "$20,000", "$25,000", "$0"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00100', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '戊公司X3年12月31日應收帳款$580,000餘額，備抵壞帳貸餘$7,000。戊公司於X3年間沖銷應收帳款 $50,000，並於X3年12月31日認列$53,000壞帳費用。戊公司X3年1月1日備抵壞帳餘額為多少？', '["借餘$7,000", "貸餘$7,000", "借餘$4,000", "貸餘$4,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00101', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司設置零用金$5,000，於撥補零用金時，借記交通費用$3,000、郵政費用$1,500、現金短溢$50，貸記 現金$4,550。試問撥補前，零用金實際剩餘金額為多少？', '["$400", "$450", "$500", "$4,550"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00102', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司採永續盤存制及平均法，X1年期初存貨400單位、單位成本$10，3月1日進貨400單位、單位成 本$14，5月10日出售700單位，8月10日進貨900單位、單位成本$16，8月20日退回供應商8月10 日購買商品200單位，10月31日出售700單位。甲公司X1年銷貨成本金額為多少？', '["$19,320", "$21,000", "$18,620", "$19,250"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00103', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司本年度之水電費用$50,000，薪資費用$30,000，銷貨收入淨額$200,000，銷貨毛利率10%，本期銷 貨成本為進貨成本的150%，期末存貨為期初存貨的40%，若當年底該公司發生火災，期末存貨全部燒毀， 則期末存貨損失金額為：', '["$30,000", "$40,000", "$60,000", "$111,111"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00104', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司在1月1日有1,800件存貨，成本為每件$18。1月份的進貨及銷貨情況如下：①1月4日銷貨1,350', '["1月7日進貨 900件，每件成本$20", "1月15日進貨600件，每件成本$22", "1月 29日銷貨900件，每件售價$32。甲公司採用永續盤存制、先進先出法，1月31日期末存貨成本為：", "$18,900"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "d892cb86a6ac", "answer_pdf_sha1": "1de06b7d4c79", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
